import{_ as t,c as r}from"./app.6aa02fdf.js";const d={},e=r('<h1 id="\u9644\u5F55-2" tabindex="-1"><a class="header-anchor" href="#\u9644\u5F55-2" aria-hidden="true">#</a> \u9644\u5F55 2</h1><h2 id="\u654F\u6377\u88C1\u526A" tabindex="-1"><a class="header-anchor" href="#\u654F\u6377\u88C1\u526A" aria-hidden="true">#</a> \u654F\u6377\u88C1\u526A</h2><table><thead><tr><th>\u60C5\u51B5</th><th>\u88C1\u526A\u5EFA\u8BAE</th></tr></thead><tbody><tr><td>\u5927\u578B\u9879\u76EE\u56E2\u961F</td><td>\u6301\u5927\u9879\u76EE\u91CD\u5EFA\u4E3A\u591A\u4E2A\u5C0F\u9879\u76EE\u3002\u9996\u5148\u5C1D\u8BD5\u6280\u672F\u5B9E\u9A8C\u9879\u76EE\uFF0C\u7136\u540E\u518D\u6267\u884C\u5B9E\u65BD\u9879\u76EE\u3002<br>\u8003\u8651\u9891\u7E41\u53D1\u5E03\u8F83\u5C11\u7684\u529F\u80FD\uFF0C\u4EE5\u521B\u5EFA\u8F83\u5C0F\u7684\u9879\u76EE\u56E2\u961F\u3002<br>\u8003\u8651\u5C06\u56E2\u961F\u88C1\u51CF\u5230\u4EC5\u5305\u542B\u5173\u952E\u6838\u5FC3\u6210\u5458\u3002\u901A\u5E38\u4EBA\u5458\u8FC7\u591A\u4F1A\u963B\u788D\u8FC7\u7A0B\u800C\u4E0D\u4F1A\u6709\u6240\u52A9\u76CA\u3002\u7F29\u5C0F\u56E2\u961F\u89C4\u6A21\u53EF\u51CF\u5C11\u5185\u90E8\u52A8\u8361\u548C\u6210\u672C\u3002<br><br>\u5C06\u5927\u578B\u56E2\u961F\u5206\u89E3\u4E3A\u591A\u4E2A\u5C0F\u56E2\u961F\uFF0C\u5E76\u5229\u7528\u9879\u76EE\u7BA1\u7406\u8FDB\u884C\u540C\u6B65\u548C\u534F\u8C03\u3002\u5229\u7528\u654F\u6377\u548C\u7CBE\u76CA\u9879\u76EE\u7BA1\u7406\u6765\u7EC4\u7EC7\u5927\u578B\u9879\u76EE\u3002<br><br>\u8003\u8651 DA\u3001SAFe \u6216 LeSS \u7B49\u5927\u89C4\u6A21\u654F\u6377\u6846\u67B6\u6216\u7CBE\u76CA\u6846\u67B6\u3002\u6BCF\u4E2A\u56E2\u961F\u90FD\u53EF\u63D0\u4F9B\u4E00\u4E9B\u6709\u7528\u7684\u89C2\u70B9\uFF0C\u5E76\u627F\u62C5\u5B9E\u65BD\u98CE\u9669\u4EE5\u53CA\u8FC7\u7A0B\u538B\u529B/\u6210\u672C\u3002</td></tr><tr><td>\u5206\u6563\u56E2\u961F</td><td>\u8BB8\u591A\u9879\u76EE\u90FD\u4F1A\u5305\u542B(\u4E00\u4E9B)\u5206\u6563\u56E2\u961F\u6210\u5458\u3002\u5373\u65F6\u4FE1\u606F\u3001\u89C6\u9891\u4F1A\u8BAE\u548C\u56E2\u961F\u7535\u5B50\u677F\u90FD\u6709\u52A9\u4E8E\u786E\u4FDD\u901A\u8BAF\u6D41\u7545\u3002<br>\u5982\u679C\u56E2\u961F\u4FDD\u6301\u7A33\u5B9A\uFF0C\u8BF7\u5C3D\u5FEB\u6784\u5EFA\u9762\u5BF9\u9762\u4F1A\u8BAE\u4EE5\u63D0\u9AD8\u672A\u6765\u8FDC\u7A0B\u4EA4\u6D41\u7684\u6548\u7387\u3002\u9762\u5BF9\u9762\u4EA4\u6D41\u65F6\u66F4\u5BB9\u6613\u5EFA\u7ACB\u4FE1\u4EFB\u611F\uFF0C\u63D0\u9AD8\u5BF9\u8BDD\u8D28\u91CF\u3002<br>\u5982\u679C\u5728\u8FDC\u7A0B\u4F1A\u8BAE\u8FC7\u7A0B\u4E2D\u53C2\u4E0E\u8005\u7F3A\u4E4F\u9762\u90E8\u8868\u60C5\u548C\u8EAB\u4F53\u8BED\u8A00\u4EA4\u6D41\uFF0C\u8BF7\u8003\u8651\u5FAA\u73AF\u63D0\u95EE\u4EE5\u786E\u8BA4\u4ED6\u4EEC\u7684\u53C2\u4E0E\u7A0B\u5EA6\u4EE5\u53CA\u5BF9\u51B3\u7B56\u662F\u5426\u8BA4\u53EF\u3002<br>\u6B64\u5916\uFF0C\u8BF7\u8003\u8651\u4F7F\u7528\u57FA\u4E8E\u8FED\u4EE3\u7684\u654F\u6377\u65B9\u6CD5\u3002\u5982\u679C\u56E2\u961F\u6210\u5458\u6240\u5728\u65F6\u533A\u5DEE\u522B\u8F83\u5927\uFF0C\u8BF7\u907F\u514D\u4F7F\u7528\u6574\u4E2A\u9879\u76EE\u8FED\u4EE3\u65B9\u5F0F\uFF0C\u800C\u662F\u9F13\u52B1\u5F00\u5C55\u66F4\u591A\u66F4\u9891\u7E41\u7684\u79C1\u4EBA\u4F1A\u8BAE(\u6BCF\u6B21\u4E24\u5230\u4E09\u4E2A\u4EBA)\u3002</td></tr><tr><td>\u67D0\u4E9B\u5B89\u5168\u5173\u952E\u578B\u4EA7\u54C1\u53EF\u80FD\u9700\u8981\u5F53\u524D\u654F\u6377\u8FC7\u7A0B\u6240\u5EFA\u8BAE\u7684\u5176\u4ED6\u6587\u6863\u53CA\u5408\u89C4\u6027\u68C0\u67E5</td><td>\u5728\u8FD9\u4E9B\u73AF\u5883\u4E2D\u4ECD\u53EF\u4F7F\u7528\u654F\u6377\u65B9\u6CD5\uFF0C\u4F46\u8FD8\u9700\u8981\u8BE5\u9886\u57DF\u6240\u8981\u6C42\u7684\u5176\u4ED6\u76F8\u5E94\u7684\u5408\u89C4\u6027\u5BA1\u67E5\u3001\u6587\u6863\u548C\u8BA4\u8BC1\u3002\u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u6587\u6863\u53EF\u80FD\u9700\u8981\u968F\u5DF2\u5B8C\u6210\u7684\u529F\u80FD\u4E00\u8D77\u4EA4\u4ED8\u3002\u53EA\u6709\u6587\u6863\u5B8C\u6210\u540E\u529F\u80FD\u624D\u7B97\u5B8C\u6210\u3002<br>\u8003\u8651\u4F7F\u7528\u6DF7\u5408\u65B9\u6CD5(\u591A\u79CD\u654F\u6377\u65B9\u6CD5)\uFF0C\u6309\u7167\u4EA7\u54C1\u73AF\u5883\u6240\u8981\u6C42\u7684\u66F4\u9AD8\u4E25\u683C\u7A0B\u5EA6\uFF0C\u4ECE\u654F\u6377\u6240\u5E26\u6765\u7684\u534F\u4F5C\u548C\u6C9F\u901A\u6539\u5584\u4E2D\u83B7\u5F97\u76CA\u5904\u3002\u822A\u7A7A\u98DE\u884C\u7CFB\u7EDF\u5F00\u53D1\u5546\u548C\u836F\u7269\u516C\u53F8\u91C7\u7528\u654F\u6377\u65B9\u6CD5\u5E76\u7ED3\u5408\u81EA\u5DF1\u7684\u5176\u4ED6\u8FC7\u7A0B\uFF0C\u5145\u5206\u5229\u7528\u8FD9\u4E9B\u4F18\u52BF\u5E76\u4FDD\u7559\u4E86\u76F8\u5E94\u7684\u63A7\u5236\u6743\u3002</td></tr><tr><td>\u7A33\u5B9A\u9700\u6C42\u548C\u6267\u884C\u8FC7\u7A0B</td><td>\u662F\u5426\u771F\u6B63\u9700\u8981\u654F\u6377\u65B9\u6CD5?\u5982\u679C\u9700\u6C42\u4E0D\u786E\u5B9A\u6027\u8F83\u4F4E\u3001\u53D8\u66F4\u901F\u5EA6\u7F13\u6162\u3001\u6216\u8005\u6267\u884C\u98CE\u9669\u5F88\u5C0F\uFF0C\u5219\u53EF\u80FD\u4E0D\u9700\u8981\u6574\u5957\u654F\u6377\u65B9\u6CD5\u3002\u5C3D\u7BA1\u534F\u4F5C\u548C\u900F\u660E\u7A0B\u5EA6\u63D0\u9AD8\u5BF9\u4EFB\u4F55\u9879\u76EE\u90FD\u6709\u76CA\u5904\uFF0C\u4F46\u67D0\u4E9B\u8FED\u4EE3\u6784\u5EFA\u548C\u5BA1\u67E5\u5468\u671F\u53EF\u80FD\u4F1A\u662F\u591A\u4F59\u7684\u3002<br>\u5982\u679C\u6784\u5EFA/\u53CD\u9988\u5468\u671F\u65E0\u6CD5\u5B9A\u671F\u53D1\u73B0\u6216\u4F18\u5316\u9700\u6C42\uFF0C\u8BF7\u8003\u8651\u5EF6\u957F\u5176\u6301\u7EED\u65F6\u95F4\u4EE5\u51CF\u5C11\u5BA1\u67E5\u65F6\u95F4\u5BF9\u6210\u672C\u7684\u5F71\u54CD\u3002<br>\u5982\u679C\u9879\u76EE\u5728\u8BBE\u8BA1\u548C\u5F00\u53D1\u671F\u95F4\u7684\u53D8\u66F4\u901F\u5EA6\u6781\u5FEB\uFF0C\u4F46\u5411\u5BA2\u6237\u4EA4\u4ED8\u662F\u4E00\u4E2A\u786E\u5B9A\u6027\u7684\u53EF\u91CD\u590D\u7684\u8FC7\u7A0B\uFF0C\u5728\u6BCF\u4E2A\u9879\u76EE\u9636\u6BB5\u91C7\u7528\u76F8\u5E94\u751F\u547D\u5468\u671F\u6A21\u578B\u7684\u6DF7\u5408\u65B9\u6CD5\u53EF\u80FD\u66F4\u6709\u610F\u4E49\u3002</td></tr><tr><td>\u56E2\u961F\u4F4D\u4E8E\u804C\u80FD\u578B\u7EC4\u7EC7\u5185\u7684\u804C\u80FD\u5B64\u5C9B\u4E2D</td><td>\u654F\u6377\u662F\u57FA\u4E8E\u8DE8\u804C\u80FD\u56E2\u961F\u7684\u7406\u5FF5\u3002\u8003\u8651\u8BA9\u8FD9\u4E9B\u5458\u5DE5\u81EA\u884C\u521B\u5EFA\u8DE8\u804C\u80FD\u56E2\u961F\uFF0C\u800C\u4E0D\u91C7\u53D6\u7BA1\u7406\u5E72\u9884\u624B\u6BB5\uFF0C\u5E76\u4E86\u89E3\u5176\u540E\u679C\u3002<br>\u5982\u679C\u80FD\u591F\u901A\u8FC7\u7EC4\u7EC7\u62A5\u916C\u7CFB\u7EDF\u8BA4\u53EF\u804C\u80FD\u9886\u57DF\u5E76\u7ED9\u4E88\u5956\u52B1\uFF0C\u8BF7\u8003\u8651\u9996\u5148\u53D8\u66F4\u8BE5\u7CFB\u7EDF\u3002\u9664\u975E\u5BF9\u81EA\u5DF1\u7684\u62A5\u916C\u6709\u4E00\u5B9A\u5F71\u54CD\uFF0C\u5458\u5DE5\u624D\u4F1A\u4E3A\u4EA7\u54C1\u6216\u56E2\u961F\u7684\u5229\u76CA\u884C\u4E8B\u3002</td></tr><tr><td>\u900F\u660E\u4F1A\u4EA7\u751F\u6050\u60E7</td><td>\u654F\u6377\u5C06\u4F1A\u521B\u5EFA\u900F\u660E\u6587\u5316: \u5458\u5DE5 \u4F1A\u5728\u6574\u4E2A\u5F00\u53D1\u671F\u95F4\u5C55\u793A\u548C\u5206\u4EAB\u5176\u6210\u679C\u3002\u8FD9\u79CD <br>\u5EA6\u7531\u56DB\u522B\u4EA4\u4ED8\u611F\u6765\u7684\u65B9\u5F0F\u6216\u53C8\u5BF9\u6210\u653F\u5F97\u7C7B\u671F\u56FD\u7BAD\u83B7\u6055\u7684\u5954\u852C\u5E26\u516C\u7684\u6001 \u5373\u53CD\u6620\u4E86\u900F\u660E\u5316\u3002 \u900F\u660E\u9700\u8981\u52C7\u6C14\u3002 <br>\u901A\u8FC7\u4F7F\u7528\u72B6\u6001\u677F\u6216\u767D\u677F,\u793A\u8303\u5F15\u5BFC\u5E76\u5728\u51B3\u7B56\u8FC7\u7A0B\u4E2D\u5C55\u793A\u900F\u660E\u5316\u3002</td></tr><tr><td>\u8BB8\u591A\u56E2\u961F\u6210\u5458\u7F3A\u4E4F\u6280\u672F\u9886\u57DF\u77E5\u8BC6</td><td>\u654F\u6377\u65B9\u6CD5\u5C06\u4F1A\u63D0\u9AD8\u56E2\u961F\u7684\u4E3B\u52A8\u6027\u5E76\u53D1\u6325\u5176\u4F18\u52BF,\u4F5C\u51FA\u5DE5\u4F5C\u5185\u5BB9\u76F8\u5173\u7684\u672C\u5730 \u51B3\u7B56,\u4F8B\u5982\u4EFB\u52A1\u5B89\u6392\u987A\u5E8F\u4EE5\u53CA\u5728\u89E3\u51B3\u95EE\u9898\u65F6\u91C7\u7528\u54EA\u79CD\u65B9\u6CD5\u3002\u5982\u679C\u5927\u591A\u6570\u56E2 <br>\u961F\u6210\u5458\u7ECF\u9A8C\u4E0D\u8DB3,\u57FA\u4E8E\u5171\u8BC6\u7684\u65B9\u6CD5\u53EF\u80FD\u4F1A\u4EA7\u751F\u95EE\u9898\u5E76\u5BFC\u81F4\u8FD4\u5DE5\u3002\u56E0\u6B64,\u5BF9 <br>\u4E8E\u8FD9\u4E9B\u56E2\u961F\u6765\u8BF4,\u5728\u83B7\u53D6\u5FC5\u8981\u6280\u80FD\u4E4B\u524D,\u4E00\u4E9B&quot;\u5206\u914D&quot;\u548C&quot;\u6307\u5BFC&quot;\u65B9\u9762\u7684 <br>\u989D\u5916\u5E2E\u52A9\u53EF\u80FD\u662F\u5FC5\u9700\u7684\u3002\u6362\u8A00\u4E4B,\u4E0D\u8981\u76F2\u76EE\u5730\u91C7\u7528\u654F\u6377\u65B9\u6CD5,\u6388\u6743\u7ECF\u9A8C\u4E0D <br>\u8DB3\u7684\u81EA\u6307\u5BFC\u56E2\u961F\u5C1D\u8BD5\u89E3\u51B3\u4E00\u5207\u95EE\u9898\u3002\u8003\u8651\u6784\u5EFA\u80FD\u529B\u4E2D\u5FC3\u4EE5\u5E2E\u52A9\u63D0\u4F9B\u6307\u5BFC\u5E76 \u79EF\u7D2F\u9886\u57DF\u77E5\u8BC6\u3002</td></tr><tr><td>\u7F3A\u4E4F\u7BA1\u7406\u5C42\u652F\u6301</td><td>\u5982\u679C\u7F3A\u4E4F\u7BA1\u7406\u5C42\u652F\u6301,\u56E2\u961F\u5C06\u4F1A\u5728\u654F\u6377\u601D\u7EF4\u6A21\u5F0F\u548C\u65B9\u6CD5\u4E0E\u66F4\u5177\u9884\u6D4B\u6027\u7684\u601D \u7EF4\u6A21\u5F0F\u548C\u65B9\u6CD5\u4E4B\u95F4\u9047\u5230\u51B2\u7A81\u3002 <br>\u6839\u636E\u7EC4\u7EC7\u9700\u6C42\u627E\u5230\u5171\u540C\u70B9\u548C\u6539\u8FDB\u4E4B\u5904,\u7136\u540E\u5229\u7528\u5B9E\u9A8C\u548C\u56DE\u987E\u53D6\u5F97\u8FDB\u5C55\u3002 <br>\u8003\u8651\u7BA1\u7406\u5C42\u6559\u80B2/\u57F9\u8BAD\u3002\u8003\u8651\u4ECE\u7CBE\u76CA\u601D\u7EF4\u65B9\u9762\u89E3\u91CA\u654F\u6377:\u5468\u671F\u77ED\u3001\u89C4\u6A21\u5C0F\u3001 <br>\u9891\u7E41\u5BA1\u67E5\u3001\u56DE\u987E\u4E0E\u5C0F\u5E45\u6539\u8FDB\u3002</td></tr><tr><td>\u654F\u6377\u672F\u8BED\u548C\u8BED\u8A00\u4E0D\u9002\u5408\u7EC4\u7EC7\u6587\u5316</td><td>\u5982\u679C\u4E0D\u662F\u654F\u6377\u8BED\u8A00,\u5C31\u4FEE\u6539\u672F\u8BED,\u8BA9\u5458\u5DE5\u4E86\u89E3\u5E76\u540C\u610F\u8FD9\u4E9B\u6D3B\u52A8\u3002\u8BF4\u660E\u6BCF\u4E2A <br>\u672F\u8BED\u7684\u7279\u5B9A\u542B\u4E49\u3002 <br>\u4F8B\u5982,\u5982\u679C\u7EC4\u7EC7\u8BA4\u4E3A &quot;\u6E38\u620F&quot;\u4E00\u8BCD\u4E0D\u591F\u4E13\u4E1A,\u8BF7\u52FF\u4F7F\u7528\u7C7B\u4F3C\u4E8E&quot;\u8BA1\u5212\u6E38 \u620F&quot;\u8FD9\u6837\u7684\u672F\u8BED,\u800C\u662F\u8003\u8651\u4F7F\u7528 &quot;\u8BA1\u5212\u7814\u8BA8\u4F1A&quot;\u8FD9\u6837\u7684\u672F\u8BED\u3002</td></tr></tbody></table>',3);function a(b,o){return e}var c=t(d,[["render",a],["__file","appendix2.html.vue"]]);export{c as default};
